_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 pixelsize = uTexSize.zw*audioLowSmooth*0.2;

float zm = q5;
vec2 cen = vec2(q11,q12) * audioLowSmooth;
vec2 uvo = (vUvOriginal-cen)*zm + cen;

vec2 uvm = vUvOriginal;

vec2 noise_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw + rand_frame.xy;
vec4 noiseVal = texture(sampler_noise_lq, noise_uv)*audioHighSmooth;

ret.xy = texture( sampler_pw_main,uvo).xy;
ret.xy = (ret.xy-cen)/zm+cen;

vec2 uv2 = vUvOriginal  + (noiseVal.xy-.5)*12*pixelsize;
vec3 rsamp = texture(sampler_pw_main,fract(uv2)).xyz;

rsamp.xy = (rsamp.xy-cen)/zm+cen;

vec4 len = (vec4(ret.xy,rsamp.xy) - uvm.xyxy);
float l1 = length(len.xy);
if (l1 > length(len.zw)) ret.xy = rsamp.xy;

uv2 = vUvOriginal  + (noiseVal.zw-.5)*48*pixelsize;
rsamp = texture(sampler_pw_main,fract(uv2)).xyz;
rsamp-=roam_sin.wzy*roam_cos.zxy;
rsamp.xy = (rsamp.xy-cen)/zm+cen;
len.zw = rsamp.xy - uvm.xy;
if (l1 > length(len.zw)) ret.xy = rsamp.xy;

//uv2 = vUvOriginal  + (noiseVal.zw-.5)*6*pixelsize;
//rsamp = texture(sampler_pw_main,fract(uv2)).xyz;
//len = abs(vec4(ret.xy,rsamp.xy) - uvm.xyxy);
//if (length(len.xy) > length(len.zw)) ret.xy = rsamp.xy;

//vec2 uvo = (vUvOriginal-cen)*zm + cen;
//if (q5) {
//ret.xy = texture( sampler_pw_main,uvo).xy;
//}

ret.z = 0;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;




vec2 uva = vUv;
vec2 uvb = vec2(1-vUv.x,vUv.y);

ret = texture(sampler_main, uva).x + texture(sampler_main, uvb).x;

vec3 blurs = GetBlur1(uva).x + GetBlur3(uva).x;
blurs += GetBlur1(uvb).x + GetBlur3(uvb).x;


vec2 uv3 = (vUv-.5)*(1-GetBlur1(vUv).zzz)+.5;
ret += clamp01(pow(texture(sampler_main, uv3).zzz,.5)*(1-ret.x*2)),
ret += clamp01(pow(GetBlur1(uv3).zzz,.5)*(1-ret.x*2)),


ret = mix(
blurs,
ret,
pow(ret,1));

ret = pow(ret,vec3(5,1,.5));

ret += pow(texture(sampler_main, vec2(vUv.x,1-vUv.y)).yyy+texture(sampler_main, 1-vUv).yyy,vec3(.6,.95,5));

ret-=roam_sin*roam_cos.zxy;

ret = ret * 0.9;
//ret = 1-ret;
ret *= audioHigh;

  fragColor = ret;
}
